// Node 3 — Fan out one item per PDF (or image) attachment
const results = [];

for (const item of $input.all()) {
  const binary = item.binary || {};
  const keys = Object.keys(binary);

  // Prefer PDFs. Only fall back to images if no PDFs at all — most image
  // attachments on invoice emails are logos in the signature, not the invoice.
  let chosenKeys = keys.filter((k) => binary[k]?.mimeType === 'application/pdf');
  if (chosenKeys.length === 0) {
    chosenKeys = keys.filter(
      (k) => binary[k]?.mimeType && binary[k].mimeType.startsWith('image/')
    );
  }

  if (chosenKeys.length === 0) {
    // Shouldn't happen if Node 2's filter is working, but bail safely
    continue;
  }

  chosenKeys.forEach((key, index) => {
    const chosen = binary[key];
    results.push({
      json: {
        ...item.json,
        _pdfFilename: chosen.fileName || `invoice_${index + 1}.pdf`,
        _pdfMimeType: chosen.mimeType,
        _attachmentIndex: index,        // 0-based position of this PDF within the email
        _attachmentCount: chosenKeys.length, // total PDFs pulled from this email
      },
      // Reassign under the known key `data` so Node 4 always finds it at item.binary.data
      binary: {
        data: chosen,
      },
    });
  });
}

return results;

// Node 4 — PDF → PNG page images (for vision models)
const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');
const os = require('os');

const DPI = 150;
const MAX_PAGES = 50;
const LD = '/opt/poppler-libs/usr-lib:/opt/poppler-libs/lib';
const results = [];

const items = $input.all();

for (let i = 0; i < items.length; i++) {
  const item = items[i];

  const binaryKey = Object.keys(item.binary || {}).find(
    (k) => item.binary[k].mimeType === 'application/pdf'
  ) || 'data';
  const binaryMeta = item.binary?.[binaryKey];

  if (!binaryMeta) {
    results.push({ json: { ...item.json, skipped: true, reason: 'no PDF binary' } });
    continue;
  }

  const workDir = fs.mkdtempSync(path.join(os.tmpdir(), 'invoice-'));
  const pdfPath = path.join(workDir, 'input.pdf');
  const outPrefix = path.join(workDir, 'page');

  try {
    // IMPORTANT — use the helper, not Buffer.from(binaryMeta.data, 'base64'):
    // n8n 1.x stores binaries on the filesystem by default, so binaryMeta.data
    // is a reference ID, NOT a base64 payload. Running Buffer.from(ref, 'base64')
    // produces garbage bytes and pdftoppm reports "Couldn't find trailer
    // dictionary". The helper handles both in-memory and filesystem modes.
    const pdfBuffer = await this.helpers.getBinaryDataBuffer(i, binaryKey);
    fs.writeFileSync(pdfPath, pdfBuffer);

    // IMPORTANT: n8n's Code node runs in a sandboxed task runner that does
    // NOT expose the `process` global, and the container's LD_LIBRARY_PATH
    // (set via ENV in Dockerfile.n8n) does NOT reach child processes spawned
    // by execSync. Fix: prepend LD_LIBRARY_PATH inline in the shell command —
    // execSync uses /bin/sh -c by default, so inline env assignment works
    // identically to a terminal prefix.
    execSync(
      `LD_LIBRARY_PATH=${LD} /usr/local/bin/pdftoppm -png -r ${DPI} -l ${MAX_PAGES} "${pdfPath}" "${outPrefix}"`,
      { stdio: 'pipe' }
    );

    const pngFiles = fs
      .readdirSync(workDir)
      .filter((f) => f.endsWith('.png'))
      .sort();

    const images = pngFiles.map((f) =>
      fs.readFileSync(path.join(workDir, f)).toString('base64')
    );

    results.push({
      json: {
        ...item.json,
        filename: binaryMeta.fileName || 'invoice.pdf',
        pageCount: images.length,
        images,
      },
      binary: item.binary,
    });
  } catch (err) {
    results.push({
      json: {
        ...item.json,
        error: true,
        errorMessage: `PDF conversion failed: ${err.message}`,
      },
      binary: item.binary,
    });
  } finally {
    try {
      for (const f of fs.readdirSync(workDir)) {
        fs.unlinkSync(path.join(workDir, f));
      }
      fs.rmdirSync(workDir);
    } catch (_) { /* best effort */ }
  }
}

return results;

// Lookup Vendor Hint drops binary data. Restore it from Gmail Trigger
// so Fan out can access the PDF attachments.
const gmailItem = $('Gmail Trigger').first();
return [{
  json: { ...$input.first().json },
  binary: gmailItem.binary,
}];

return $input.all().map(item => {
  const images = item.json.images || [];
  const extractionHint = item.json['Extraction Hint'] || 'none';

  const textPart = {
    text: 'You are an invoice-processing assistant for Levan Media & Marketing. Look at ALL the attached page images and extract every invoice found. Some invoices may span multiple pages — treat consecutive pages belonging to the same invoice as a single invoice.

Vendor hint (may be empty): ' + extractionHint + '

Return a JSON array where each element is one invoice. Each element must have:
- is_invoice: boolean — true only if clearly a vendor invoice
- vendor_name: string
- sender_email: string or null
- invoice_number: string — copy EXACTLY the value next to 'Invoice #', digit for digit
- invoice_date: YYYY-MM-DD
- due_date: YYYY-MM-DD or null
- payment_terms: string or null
- description: string — one-line summary
- gross_sale: number — subtotal BEFORE discount
- discount_adjustment: number — 0 if none
- total_due: number
- advertiser: string
- confidence: number 0-1

Omit non-invoice pages. Return ONLY a valid JSON array — no prose, no markdown, no code fences. Numbers as plain numbers, no currency symbols.'
  };

  return {
    json: {
      requestBody: {
        contents: [{ parts: [textPart, ...images.map(img => ({ inline_data: { mime_type: 'image/png', data: img } }))] }],
        generationConfig: { temperature: 0.1, response_mime_type: 'application/json' }
      }
    }
  };
});

const results = [];

const allItems = $input.all();
for (let sourceIndex = 0; sourceIndex < allItems.length; sourceIndex++) {
  const item = allItems[sourceIndex];
  let invoiceArray;

  try {
    const candidate = item.json.candidates?.[0];
    const finishReason = candidate?.finishReason;
    const raw = candidate?.content?.parts?.[0]?.text;

    if (!raw) {
      throw new Error(
        `Gemini response missing candidates[0].content.parts[0].text — finishReason was "${finishReason}".`
      );
    }
    if (finishReason && finishReason !== 'STOP') {
      throw new Error(`Gemini finishReason="${finishReason}" — output may be incomplete.`);
    }

    const parsed = JSON.parse(raw);
    // Handle both array response (multi-invoice) and single object (legacy)
    invoiceArray = Array.isArray(parsed) ? parsed : [parsed];
  } catch (err) {
    results.push({
      json: {
        route: 'error',
        errorMessage: `Failed to parse Gemini response: ${err.message}`,
        rawResponse: item.json,
      },
    });
    continue;
  }

  for (const data of invoiceArray) {
    if (data.is_invoice === false) {
      // silently skip non-invoice pages — they are expected in multi-invoice PDFs
      continue;
    }

    const requiredFields = ['vendor_name', 'invoice_number', 'gross_sale', 'total_due'];
    const missing = requiredFields.filter(
      (f) => data[f] === null || data[f] === undefined || data[f] === ''
    );

    if (missing.length > 0) {
      results.push({
        json: {
          route: 'error',
          _sourceIndex: sourceIndex,
          errorMessage: `Missing required fields: ${missing.join(', ')}`,
          partialData: data,
        },
      });
      continue;
    }

    const gross = Number(data.gross_sale) || 0;
    const totalDue = Number(data.total_due) || 0;
    const discount = data.discount_adjustment != null
      ? Number(data.discount_adjustment)
      : Math.max(0, gross - totalDue);

    results.push({
      json: {
        route: 'invoice',
        _sourceIndex: sourceIndex,
        row: {
          'Date Received': new Date().toISOString().split('T')[0],
          'Vendor Name': data.vendor_name,
          'Invoice Number': data.invoice_number,
          'Invoice Date': data.invoice_date || '',
          'Due Date': data.due_date || '',
          'Description': data.description || '',
          'Gross Sale': gross,
          'Discount/Adjustment': discount,
          'Payment Terms': data.payment_terms || '',
          'Status': 'Pending Review',
          'Advertiser': data.advertiser || '',
          'Sender Email': data.sender_email
            || $('Gmail Trigger').first().json.from?.value?.[0]?.address
            || '',
          'Confidence': data.confidence || 0,
        },
        extractedData: data,
      },
    });
  }
}

return results;

const fanOutItems = $('Fan out each PDF attachment').all();
return $input.all().map((item) => ({
  json: item.json,
  binary: fanOutItems[item.json._sourceIndex ?? 0].binary,
}));

// Sanitize advertiser name for use as a Google Sheets tab name.
// Sheet tab rules: max 100 chars, no [ ] * ? : / \
return $input.all().map((item, i) => {
  const parseItem = $('Parse & Validate').all()[i];
  const advertiserRaw = parseItem?.json?.row?.Advertiser || 'Unknown Advertiser';
  const advertiserName = advertiserRaw
    .replace(/[\[\]*?:\/\\]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .substring(0, 100) || 'Unknown Advertiser';
  return {
    json: {
      ...item.json,
      advertiserName
    }
  };
});

// Find the numeric sheetId for the advertiser tab by matching its title.
// We need this to call updateDimensionProperties (which requires sheetId, not name).
const advertiserName = $('Prepare Advertiser Tab').item.json.advertiserName;
const sheets = $input.first().json.sheets || [];
const match = sheets.find(s => s.properties?.title === advertiserName);
const advertiserSheetId = match?.properties?.sheetId ?? null;

return $input.all().map(item => ({
  json: {
    ...item.json,
    advertiserName,
    advertiserSheetId
  }
}));

